        let p = jjtlg_FundusProfile {
            alias: "jjfu-full-cerebro".to_string(),
            host: JJTLG_HOST_CEREBRO.to_string(),
            user: JJTLG_ACCOUNT_FULL.to_string(),
            reldir: JJTLG_RELDIR.to_string(),
